  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasProcedures ?child ; p:hasHospitals ?parent . } GROUP BY ?child }
  ?child p:Description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hospitals } }
  FILTER(?nf = ?total)
} }
